   102→router.post("/payments/webhook", async (req: Request, res: Response) => {
   103→  const secret = process.env.MP_WEBHOOK_SECRET;
   104→  if (secret) {
   105→    const xSignature = req.headers["x-signature"] as string | undefined;
   106→    const xRequestId = req.headers["x-request-id"] as string | undefined;
   107→    if (!xSignature) {
   108→      req.log.warn("MP webhook rejected: secret configured but no x-signature header");
   109→      res.status(200).json({ ok: true });
   110→      return;
   111→    }
   112→    const parts: Record<string, string> = {};
   113→    xSignature.split(",").forEach((p) => {
   114→      const [k, v] = p.trim().split("=");
   115→      if (k && v) parts[k] = v;
   116→    });
   117→    const ts = parts["ts"];
   118→    const v1 = parts["v1"];
   119→    if (!ts || !v1) {
   120→      req.log.warn("MP webhook rejected: malformed x-signature header");
   121→      res.status(200).json({ ok: true });
   122→      return;
   123→    }
   124→    const dataId = (req.query.id as string) ?? (req.body as { data?: { id?: string } })?.data?.id ?? "";
   125→    const manifest = `id:${dataId};request-id:${xRequestId ?? ""};ts:${ts};`;
   126→    const hmac = crypto.createHmac("sha256", secret).update(manifest).digest("hex");
   127→    if (hmac !== v1) {
   128→      req.log.warn({ manifest, hmac, v1 }, "MP webhook signature mismatch");
   129→      res.status(200).json({ ok: true });
   130→      return;
   131→    }
   132→  }
   133→
   134→  const body = req.body as { type?: string; data?: { id?: string } };
   135→  const paymentId = body.data?.id ?? (req.query.id as string | undefined);
   136→  const topic = body.type ?? (req.query.topic as string | undefined);
   137→
   138→  if (topic !== "payment" || !paymentId) {
   139→    res.status(200).json({ ok: true });
   140→    return;
   141→  }
   142→
   143→  try {
   144→    const token = process.env.MP_ACCESS_TOKEN;
   145→    if (!token) {
   146→      res.status(200).json({ ok: true });
   147→      return;
   148→    }
   149→
   150→    const payRes = await fetch(`https://api.mercadopago.com/v1/payments/${paymentId}`, {
   151→      headers: { Authorization: `Bearer ${token}` },
   152→    });
   153→    if (!payRes.ok) {
   154→      res.status(200).json({ ok: true });
   155→      return;
   156→    }
   157→
   158→    const payment = (await payRes.json()) as {
   159→      status: string;
   160→      external_reference?: string;
   161→      id: number;
   162→      transaction_amount?: number;
   163→    };
   164→
   165→    const mpPaymentIdStr = String(payment.id);
   166→
   167→    if (payment.external_reference) {
   168→      const parts = payment.external_reference.split("|");
   169→      const userId = parts[0];
   170→      const planId = parts[1];
   171→
   172→      if (!userId || !planId) {
   173→        res.status(200).json({ ok: true });
   174→        return;
   175→      }
   176→
   177→      // — Idempotency: skip if this exact payment was already processed —
   178→      const [existingEvent] = await db
   179→        .select({ id: paymentEventsTable.id, status: paymentEventsTable.status })
   180→        .from(paymentEventsTable)
   181→        .where(eq(paymentEventsTable.mpPaymentId, mpPaymentIdStr))
   182→        .limit(1);
   183→
   184→      if (existingEvent) {
   185→        req.log.info({ mpPaymentId: mpPaymentIdStr }, "MP webhook: payment already processed, skipping");
   186→        res.status(200).json({ ok: true });
   187→        return;
   188→      }
   189→
   190→      // — Record the payment event —
   191→      await db.insert(paymentEventsTable).values({
   192→        id: crypto.randomUUID(),
   193→        userId,
   194→        mpPaymentId: mpPaymentIdStr,
   195→        plan: planId,
   196→        amount: payment.transaction_amount ? Math.round(payment.transaction_amount) : null,
   197→        status: payment.status,
   198→        description: PLANS[planId]?.name ?? planId,
   199→      }).onConflictDoNothing();
   200→
   201→      // — Handle approved payment: activate subscription —
