   203→        const periodEnd = new Date();
   204→        periodEnd.setMonth(periodEnd.getMonth() + 1);
   205→
   206→        await db.transaction(async (tx) => {
   207→          const existing = await tx
   208→            .select({ id: subscriptionsTable.id })
   209→            .from(subscriptionsTable)
   210→            .where(eq(subscriptionsTable.userId, userId))
   211→            .limit(1);
   212→
   213→          if (existing.length > 0) {
   214→            await tx
   215→              .update(subscriptionsTable)
   216→              .set({
   217→                plan: planId,
   218→                status: "active",
   219→                mpPaymentId: mpPaymentIdStr,
   220→                currentPeriodEnd: periodEnd,
   221→              })
   222→              .where(eq(subscriptionsTable.userId, userId));
   223→          } else {
   224→            await tx.insert(subscriptionsTable).values({
   225→              id: crypto.randomUUID(),
   226→              userId,
   227→              plan: planId,
   228→              status: "active",
   229→              mpPaymentId: mpPaymentIdStr,
   230→              currentPeriodEnd: periodEnd,
   231→            }).onConflictDoNothing();
   232→          }
